const body = $input.first().json.body || $input.first().json;
const spec = body.spec || '';
const allFiles = body.all_files || ['models.py', 'routes.py', 'main.py', 'test_main.py'];

if (!spec) throw new Error('Missing required field: spec');

const systemPrompt = `You are a senior QA engineer writing acceptance tests from a PRD.
You have NOT seen any implementation code. Write tests based ONLY on the spec below.
Your tests will be run against code written by a different engineer — they must FAIL if the spec is not implemented correctly.

Rules for test_main.py:
- Use pytest + httpx async: from httpx import AsyncClient, ASGITransport
  async with AsyncClient(transport=ASGITransport(app=app), base_url='http://test') as client:
- Import app from main: from main import app
- Mark every test: @pytest.mark.asyncio
- Add autouse fixture at the top to reset global state:
    import routes
    @pytest.fixture(autouse=True)
    def reset_stores():
        for name, attr in vars(routes).items():
            if not name.startswith('_') and isinstance(attr, dict): attr.clear()
        for name, attr in vars(routes).items():
            if not name.startswith('_') and isinstance(attr, int): setattr(routes, name, 1)
- For each Acceptance Criterion in the spec, write one test that:
    - Sets up the precondition (POST to create resources)
    - Calls the endpoint being tested
    - Asserts the EXACT value the spec mandates (e.g., if spec says 10% fee on $100 sale, assert seller_net == "90.00")
- Include HTTP status code assertions (assert response.status_code == 200)
- Test names must match the AC they verify: test_<ac_description>

Implementation files that will exist (do NOT import or define their internals — just import app):
${allFiles.filter(f => f !== 'test_main.py').map(f => '- ' + f).join('\n')}

Start your response with exactly: # FILE: test_main.py
Then the complete test file. No markdown fences, no explanations.`;

const ollamaBody = JSON.stringify({
  model: 'qwen2.5-coder:32b',
  stream: false,
  options: { temperature: 0.1 },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: 'PRD (write tests for ALL acceptance criteria):\n\n' + spec }
  ]
});

return [{ json: { ollamaBody } }];

const raw = $input.first().json.message?.content || '';

const cleaned = raw
  .replace(/^```[\w]*\n?/m, '')
  .replace(/\n?```$/m, '')
  .trim();

const filenameMatch = cleaned.match(/^# FILE: (.+)/m);
const filename = filenameMatch ? filenameMatch[1].trim() : 'test_main.py';

const lines = cleaned.split('\n').length;

return [{ json: { filename, content: cleaned, lines } }];
